hi_preds, hi_refs = [], []
te_preds, te_refs = [], []
ta_preds, ta_refs = [], []
bn_preds, bn_refs = [], []

for item in dataset:
    hi_preds.append(translate_paragraph(item["src"], "eng_Latn", "hin_Deva"))
    te_preds.append(translate_paragraph(item["src"], "eng_Latn", "tel_Telu"))
    ta_preds.append(translate_paragraph(item["src"], "eng_Latn", "tam_Taml"))
    bn_preds.append(translate_paragraph(item["src"], "eng_Latn", "ben_Beng"))

    hi_refs.append(item["ref_hi"])
    te_refs.append(item["ref_te"])
    ta_refs.append(item["ref_ta"])
    bn_refs.append(item["ref_bn"])

print("\n===== FINAL SCORES =====")
print("Hindi BLEU:", bleu.corpus_score(hi_preds, [hi_refs]))
print("Hindi chrF:", chrf.corpus_score(hi_preds, [hi_refs]))
print("Telugu BLEU:", bleu.corpus_score(te_preds, [te_refs]))
print("Telugu chrF:", chrf.corpus_score(te_preds, [te_refs]))
print("Tamil BLEU:", bleu.corpus_score(ta_preds, [ta_refs]))
print("Tamil chrF:", chrf.corpus_score(ta_preds, [ta_refs]))
print("Bengali BLEU:", bleu.corpus_score(bn_preds, [bn_refs]))
